[Fact]
public void AddRow_EnforceColumnDefinitionAndCountValidation()
{
    // Arrange
    var table = new ConsoleTable();

    // Act & Assert: Verify that rows cannot be added before columns are defined
    var missingColumnsException = Assert.Throws<Exception>(() => table.AddRow("Test Value"));
    Assert.Equal("Please set the columns first", missingColumnsException.Message);

    // Act: Define two columns
    table.AddColumn(new[] { "Column1", "Column2" });

    // Act & Assert: Verify that row value count must match the count of defined columns
    var countMismatchException = Assert.Throws<Exception>(() => table.AddRow("Value 1"));
    Assert.Contains("does not match the values", countMismatchException.Message);

    // Act: Add a valid row that matches the column count
    table.AddRow("Value 1", "Value 2");

    // Assert: Verify row was added successfully after validation passes
    Assert.Single(table.Rows);
    Assert.Equal(2, table.Columns.Count);
}

[Fact]
public void CellContentExceedingMaxWidthShouldWrapIntoSubsequentRowsAtWordBoundaries()
{
    // Arrange
    // Create a table with a single column and a small MaxWidth to trigger wrapping logic.
    var table = new ConsoleTable("Description");
    table.MaxWidth = 7;
    table.SetWordBreakDelimiter(' ');

    // Add a row where the content "Long Word" (9 characters) exceeds the MaxWidth of 7.
    // The logic should look back for the last ' ' before the 7th character.
    // "Long Wo" is the first 7 characters; the last space is at index 4.
    // "Long" should remain in the first row, "Word" should move to a new subsequent row.
    table.AddRow("Long Word");

    // Act
    // ToString calls SetFormats internally which performs the row insertion logic.
    var result = table.ToString();

    // Assert
    // Verify that the individual words are preserved and readable in the output.
    Assert.Contains("Long", result);
    Assert.Contains("Word", result);

    // Verify that the row count has increased to 2, indicating a successful wrap into a subsequent row.
    // The EnableCount option is true by default or enabled in the string output.
    Assert.Contains("Count: 2", result);
}
